package be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.AantalRszDagen;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PrestatieSamenvatting;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.Money;
import lombok.AllArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.Collection;

@Slf4j
@AllArgsConstructor
public class WerkbonusReferentieLoon {

    private static final LocalDate VERANDERING_REDENERING_2023 = new LocalDate(2023, 7, 1);

    private final WerkbonusKomtInAanmerking komtInAanMerking;

    public Money bereken(
            LoonElementManager manager, PrestatieSamenvatting prestatieSamenvatting, SleutelGegevens gegevens, RekenTijd rekenTijd,
            BigDecimal referentieMaatman) {
        Collection<LoonElement> aggregaatElementen = gegevens.getOpperElementen(manager);
        Money referentieLoon = Money.ZERO;
        for (LoonElement aggregaatElement : aggregaatElementen) {
            if (komtInAanMerking.checkLoonElement(gegevens, aggregaatElement, rekenTijd)) {
                referentieLoon = referentieLoon.add(aggregaatElement.getPropertyMoney(getBasisKey(rekenTijd)));
            }
        }
        BigDecimal hWaarde = prestatieSamenvatting.getHwaarde();
        if (hWaarde.signum() > 0) {
            BigDecimal weekdagen = AantalRszDagen.inMaand(5, rekenTijd.rekenPeriode);
            BigDecimal maatman = gegevens.getMaatman();
            if (RekenTools.isOnregelmatigPerPrestatieOfPerUur(maatman)) {
                maatman = referentieMaatman;
            }
            BigDecimal uren = maatman.multiply(weekdagen).divide(BigDecimal.valueOf(5), 3, RoundingMode.HALF_UP);
            referentieLoon = referentieLoon.divide(hWaarde).round(2).multiply(uren).round(2);
        }
        log.debug("referentieLoon:{}", referentieLoon);
        return referentieLoon;
    }

    private RekenBrutoKey getBasisKey(RekenTijd rekenTijd) {
        if (rekenTijd.beginDatum.isBefore(VERANDERING_REDENERING_2023)) {
            return RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY;
        } else {
            return RekenBrutoKey.BRUTO_MAANDLOON_KEY;
        }
    }


}
